UPDATE questions SET o = '["Choosed","Choosen","Chose","Choicing"]'::jsonb, c = 2, e = 'Choose — неправильный глагол. Формы: choose → chose (Past Simple) → chosen (Past Participle). Choosed и Choicing — ошибочные формы.' WHERE id = 'f211dd22-2bbc-4bb0-bae5-c9ceeffa1520';
UPDATE questions SET o = '["истина, если операнды различны","истина, если оба операнда истинны","истина, если оба операнда ложны","всегда истина, если хотя бы один операнд истинен"]'::jsonb, c = 0, e = 'XOR (исключающее ИЛИ) возвращает истину только когда операнды различны: 1⊕0=1, 0⊕1=1, но 1⊕1=0, 0⊕0=0.' WHERE id = 'cc7e3dc0-7102-413e-83df-f05ad84cd8be';
UPDATE questions SET o = '["1/(2√x)","2√x","(√x)/2","1/√x"]'::jsonb, c = 0, e = '(√x)'' = (x^½)'' = (1/2)·x^(−1/2) = 1/(2√x). По формуле степенной производной: (x^n)'' = n·x^(n−1).' WHERE id = '6106a215-e960-433f-ba1e-8455cc6a0396';
UPDATE questions SET o = '["x=−1 (макс), x=1 (мин)","x=0 (макс)","x=−1 (мин), x=1 (макс)","x=±√3 (мин, макс)"]'::jsonb, c = 0, e = 'f''(x)=3x²−3=0 → x=±1. f''''(x)=6x. f''''(−1)=−6<0 → максимум. f''''(1)=6>0 → минимум.' WHERE id = '4dbee807-6e61-401d-bd25-46a34cbc78aa';
UPDATE questions SET e = 'Число перестановок из n элементов: n! (n факториал). P₄ = 4! = 4×3×2×1 = 24. Перестановки показывают, сколькими способами можно расположить все элементы в ряд.' WHERE id = '079a55d8-c0a5-4ae3-8f6d-1c6ae1c9a593';
