UPDATE questions SET e = 'Площадь круга S = πR². S = π×5² = 25π ≈ 78.54. Не путать с длиной окружности C = 2πR.' WHERE id = 'f3b9c741-72be-4329-a6d3-6bc51bf39c46';
UPDATE questions SET e = 'Диагональ квадрата d = a√2 (теорема Пифагора: d²=a²+a²=2a²). d = 6√2 ≈ 8.49.' WHERE id = '2be06af1-7885-45d3-a76e-c6f9af506600';
